public function finalizeScopes(
    array $scopes,
    string $grantType,
    ClientEntityInterface $clientEntity,
    ?string $userIdentifier = null,
    ?string $authCodeId = null
): array {
    return collect($scopes)
        ->unless(in_array($grantType, ['password', 'personal_access', 'client_credentials']),
            fn (Collection $scopes): Collection => $scopes->reject(
                fn (ScopeEntityInterface $scope): bool => $scope->getIdentifier() === '*'
            )
        )
        ->filter(fn (ScopeEntityInterface $scope): bool => Passport::hasScope($scope->getIdentifier()))
        ->when($this->clients->findActive($clientEntity->getIdentifier()),
            fn (Collection $scopes, Client $client): Collection => $scopes->filter(
                fn (ScopeEntityInterface $scope): bool => $client->hasScope($scope->getIdentifier())
            )
        )
        ->values()
        ->all();
}

for ($a = 1; $a <= $attempts; $a++) {
    if ($this->getDriverName() === 'sqlsrv') {
        return parent::transaction($callback, $attempts);
    }

    $this->getPdo()->exec('BEGIN TRAN');

    // We'll simply execute the given callback within a try / catch block
    // and if we catch any exception we can rollback the transaction
    // so that none of the changes are persisted to the database.
    try {
        $result = $callback($this);

        $this->getPdo()->exec('COMMIT TRAN');
    }

    // If we catch an exception, we will rollback so nothing gets messed
    // up in the database. Then we'll re-throw the exception so it can
    // be handled how the developer sees fit for their applications.
    catch (Throwable $e) {
        $this->getPdo()->exec('ROLLBACK TRAN');

        throw $e;
    }

    return $result;
}

foreach ($pattern as $pattern) {
    $pattern = (string) $pattern;

    // If the given value is an exact match we can of course return true right
    // from the beginning. Otherwise, we will translate asterisks and do an
    // actual pattern match against the two strings to see if they match.
    if ($pattern === '*' || $pattern === $value) {
        return true;
    }

    if ($ignoreCase && mb_strtolower($pattern) === mb_strtolower($value)) {
        return true;
    }

    $pattern = preg_quote($pattern, '#');

    // Asterisks are translated into zero-or-more regular expression wildcards
    // to make it convenient to check if the strings starts with the given
    // pattern such as "library/*", making any string check convenient.
    $pattern = str_replace('\*', '.*', $pattern);

    if (preg_match('#^'.$pattern.'\z#'.($ignoreCase ? 'isu' : 'su'), $value) === 1) {
        return true;
    }
}

foreach ($resourceClasses as $resource) {
    foreach ($resource::getPages() as $pageRegistration) {
        $this->queueLivewireComponentForRegistration($pageRegistration->getPage());
    }

    foreach ($resource::getRelations() as $relation) {
        if ($relation instanceof RelationGroup) {
            foreach ($relation->getManagers() as $groupedRelation) {
                $this->queueLivewireComponentForRegistration($this->normalizeRelationManagerClass($groupedRelation));
            }

            continue;
        }

        $this->queueLivewireComponentForRegistration($this->normalizeRelationManagerClass($relation));
    }

    foreach ($resource::getWidgets() as $widget) {
        $this->queueLivewireComponentForRegistration($this->normalizeWidgetClass($widget));
    }
}

if (! $shouldCheckPolicyExistence) {
    if (
        Filament::isAuthorizationStrict()
        && (! Gate::forUser($user)->has($action))
        && (
            blank($policyClass = Gate::getPolicyFor($model))
            || (! method_exists($policyClass, $actionValue))
        )
    ) {
        $modelName = is_string($model) ? $model : $model::class;

        throw new LogicException(blank($policyClass)
            ? "Strict authorization mode is enabled, but no ability [{$actionValue}] or policy with method [{$actionValue}()] was found for [{$modelName}]."
            : "Strict authorization mode is enabled, but no ability [{$actionValue}] or [{$actionValue}()] method was found on [{$policyClass}].");
    }

    return Gate::forUser($user)->inspect($action, Arr::wrap($model));
}

foreach ($schema->getComponents(withActions: false, withHidden: true) as $childComponent) {
    if (
        ($childComponent->getStatePath() === $component->getStatePath()) &&
        ($childComponent->getModel() === $component->getModel()) &&
        ($childComponent->getRecord() === $component->getRecord()) &&
        ($childComponent instanceof CanEntangleWithSingularRelationships) &&
        ($childComponent->getRelationshipName() === $component->getRelationshipName()) &&
        ($childComponent->hasRelationship())
    ) {
        return $childComponent;
    }

    foreach ($childComponent->getChildSchemas() as $schema) {
        $found = $findFirstComponentWithThisRelationship($schema);

        if ($found) {
            return $found;
        }
    }
}

if (! ($this->components instanceof Closure)) {
    $this->components = array_map(
        fn (Component | Action | ActionGroup | string | Htmlable $component): Component | Action | ActionGroup | string | Htmlable => match (true) {
            $component instanceof Action, $component instanceof ActionGroup => (clone $component)
                ->schemaContainer($this),
            $component instanceof Component => $component
                ->container($this)
                ->getClone(),
            default => $component,
        },
        Arr::wrap($this->components),
    );

    $this->cachedComponents = null;
    $this->cachedFlatComponents = [];
    $this->cachedComponentsByStatePath = [];
}

foreach ($this->getCachedSchemas() as $schema) {
    if (! $schema instanceof Schema) {
        continue;
    }

    foreach ($schema->getFlatComponents() as $component) {
        if (! $component instanceof Field) {
            continue;
        }

        if ($component->getStatePath() !== $statePath) {
            continue;
        }

        if ($component instanceof BaseFileUpload) {
            return $component;
        }

        if (
            in_array(HasFileAttachments::class, class_uses_recursive($component), strict: true) &&
            method_exists($component, 'hasFileAttachments') &&
            $component->hasFileAttachments()
        ) {
            return $component;
        }
    }
}

if ($this->queriesRelationships()) {
    $field
        ->relationship(
            $this->getRelationshipName(),
            $this->getRelationshipTitleAttribute(),
            $this->modifyRelationshipQueryUsing,
        )
        ->getSearchResultsUsing(fn (Select $component, ?string $search): array => $this->getSearchResultsFromRelationship($component, $search))
        ->options(fn (Select $component): ?array => $this->getOptionsFromRelationship($component))
        ->getOptionLabelUsing(fn (Select $component) => $this->getOptionLabelFromRelationship($component))
        ->getOptionLabelsUsing(fn (Select $component, array $values): array => $this->getOptionLabelsFromRelationship($component, $values))
        ->forceSearchCaseInsensitive($this->isSearchForcedCaseInsensitive());
} else {
    $field->options(fn (): array => $this->getOptions());
}

if ($newTransactionLevel === 0) {
    $this->removeAllTransactionsForConnection($connection);
} else {
    $this->pendingTransactions = $this->pendingTransactions->reject(
        fn ($transaction) => $transaction->connection == $connection &&
                             $transaction->level > $newTransactionLevel
    )->values();

    if ($this->currentTransaction) {
        do {
            $this->removeCommittedTransactionsThatAreChildrenOf($this->currentTransaction[$connection]);

            $this->currentTransaction[$connection]->executeCallbacksForRollback();

            $this->currentTransaction[$connection] = $this->currentTransaction[$connection]->parent;
        } while (
            isset($this->currentTransaction[$connection]) &&
            $this->currentTransaction[$connection]->level > $newTransactionLevel
        );
    }
}

foreach ($errors as $key => $value) {
    if (is_int($key)) {
        $this->assertJsonValidationErrorFor($value, $responseKey);

        continue;
    }

    $this->assertJsonValidationErrorFor($key, $responseKey);

    foreach (Arr::wrap($value) as $expectedMessage) {
        $errorMissing = true;

        foreach (Arr::wrap($jsonErrors[$key]) as $jsonErrorMessage) {
            if (Str::contains($jsonErrorMessage, $expectedMessage)) {
                $errorMissing = false;

                break;
            }
        }

        if ($errorMissing) {
            PHPUnit::withResponse($this)->fail(
                "Failed to find a validation error in the response for key and message: '$key' => '$expectedMessage'".PHP_EOL.PHP_EOL.$errorMessage
            );
        }
    }
}

foreach ((new ReflectionClass($this->component))->getProperties() as $property) {
    // Public properties only...
    if ($property->isPublic() !== true) continue;
    // Uninitialized properties only...
    if ($property->isInitialized($this->component)) continue;

    $type = $property->getType();

    if (! $type instanceof ReflectionNamedType) continue;

    $typeName = $type->getName();

    // "Form" object property types only...
    if (! is_subclass_of($typeName, Form::class)) continue;

    $form = new $typeName(
        $this->component,
        $name = $property->getName()
    );

    $callBootMethod = FormObjectSynth::bootFormObject($this->component, $form, $name);

    $property->setValue($this->component, $form);

    $callBootMethod();
}

foreach (Route::getRoutes() as $route) {
    $uses = $route->action['uses'] ?? null;

    if (! is_string($uses)) continue;

    // Check if this route uses LivewirePageController (indicates Route::livewire() was used)
    if (str_contains($uses, LivewirePageController::class)) {
        $routeComponent = $route->action['livewire_component'] ?? null;

        if (! $routeComponent) continue;

        // Resolve the component class name (handles both class strings and component names)
        $resolvedClass = is_string($routeComponent) && class_exists($routeComponent)
            ? $routeComponent
            : app('livewire.factory')->resolveComponentClass($routeComponent);

        if ($resolvedClass === $componentClass) {
            return url($route->uri());
        }
    }
}

if (! ($table->getRelationship() instanceof BelongsToMany && $table->allowsDuplicates())) {
    if ($this->isTrackingDeselectedTableRecords) {
        $query = $table->getQuery()->whereKeyNot($this->deselectedTableRecords);
    } else {
        $query = $table->getQuery()->whereKey($this->selectedTableRecords);
    }

    if ($maxSelectableRecords) {
        $query->limit($maxSelectableRecords);
    }

    if (! $chunkSize) {
        $this->applySortingToTableQuery($query);
    }

    if ($shouldFetchSelectedRecords) {
        foreach ($this->getTable()->getColumns() as $column) {
            $column->applyEagerLoading($query);
            $column->applyRelationshipAggregates($query);
        }
    }

    if ($table->shouldDeselectAllRecordsWhenFiltered()) {
        $this->filterTableQuery($query);
    }

    return $query;
}

if ($parent instanceof UrlRoutable &&
                ! $route->preventsScopedBindings() &&
