        return (($this->position ?? filament()->getDatabaseNotificationsPosition()) === DatabaseNotificationsPosition::Topbar)
            ? view('filament-panels::components.topbar.database-notifications-trigger')
            : view('filament-panels::components.sidebar.database-notifications-trigger');
    }
}

foreach ($this->getComponents(withActions: false, withHidden: true) as $component) {
    if (! $component->isDehydrated()) {
        continue;
    }

    foreach ($component->getChildSchemas(withHidden: true) as $childSchema) {
        if ($childSchema->isHiddenAndNotDehydratedWhenHidden()) {
            continue;
        }

        $childSchema->mutateDehydratedState($state);
    }

    if (filled($component->getStatePath(isAbsolute: false))) {
        if (! $component->mutatesDehydratedState()) {
            continue;
        }

        $componentStatePath = $component->getStatePath();

        data_set(
            $state,
            $componentStatePath,
            $component->mutateDehydratedState(data_get($state, $componentStatePath)),
        );
    }
}

try {
    $result = $component->{$method}(...$params);

    $returnEarly($result);
} catch (ValidationException $e) {
    // Add validation errors to returnsMeta effect keyed by action index
    $existingMeta = $context->effects['returnsMeta'] ?? [];
    $existingMeta[$index] = ['errors' => $e->errors()];
    $context->addEffect('returnsMeta', $existingMeta);

    // Return null so the returns array stays aligned
    $returnEarly(null);
} catch (\Throwable $e) {
    $status = $e instanceof HttpExceptionInterface ? $e->getStatusCode() : 500;

    $existingMeta = $context->effects['returnsMeta'] ?? [];
    $existingMeta[$index] = ['status' => $status];
    $context->addEffect('returnsMeta', $existingMeta);

    $returnEarly(null);
}

protected function getSynthesizerByTarget($target, $context, $path)
    {
        // Performance optimization: Cache synthesizer matches by runtime type...
        $type = get_debug_type($target);

        if (! isset($this->synthesizerTypeCache[$type])) {
            foreach ($this->propertySynthesizers as $synth) {
                if ($synth::match($target)) {
                    $this->synthesizerTypeCache[$type] = $synth;

                    return new $synth($context, $path);
                }
            }

            throw new \Exception('Property type not supported in Livewire for property: ['.json_encode($target).']');
        }

        return new $this->synthesizerTypeCache[$type]($context, $path);
    }

static function getPreviouslyRenderedChild($parent, $key)
    {
        $child = store($parent)->get('previousChildren')[$key];

        [$tag, $childId] = $child;

        // Validate tag name - only allow valid HTML tag characters (letters, numbers, hyphens)
        // Must start with a letter to be a valid HTML tag
        if (! preg_match('/^[a-zA-Z][a-zA-Z0-9\-]*$/', $tag)) {
            throw new \Exception('Invalid Livewire child tag name. Tag names must only contain letters, numbers, and hyphens.');
        }

        // Validate child ID format - only allow alphanumeric and hyphens
        if (! preg_match('/^[a-zA-Z0-9\-]+$/', $childId)) {
            throw new \Exception('Invalid Livewire child component ID format.');
        }

        return $child;
    }

function component($name, $class = null)
    {
        $this->addComponent($name, class: $class);
    }

    function addComponent($name, $viewPath = null, $class = null)
    {
        app('livewire.finder')->addComponent($name, class: $class, viewPath: $viewPath);
    }

    function addLocation($viewPath = null, $classNamespace = null)
    {
        return app('livewire.finder')->addLocation(classNamespace: $classNamespace, viewPath: $viewPath);
    }

    function addNamespace($namespace, $viewPath = null, $classNamespace = null, $classPath = null, $classViewPath = null)
    {
        return app('livewire.finder')->addNamespace($namespace, classNamespace: $classNamespace, viewPath: $viewPath, classPath: $classPath, classViewPath: $classViewPath);
    }

if ($response instanceof DenyResponse) {
    $responseKey = $response->getKey();

    $authorizationResponses[$responseKey] ??= $response;
    $failureCountsByAuthorizationResponse[$responseKey] ??= 0;
    $failureCountsByAuthorizationResponse[$responseKey]++;
} elseif (filled($responseMessage = $response->message())) {
    $responseKey = array_search($responseMessage, $authorizationResponses);

    if ($responseKey === false) {
        $authorizationResponses[] = $responseMessage;
        $responseKey = array_key_last($authorizationResponses);
        $failureCountsByAuthorizationResponse[$responseKey] = 0;
    }

    $failureCountsByAuthorizationResponse[$responseKey]++;
} else {
    $failureCountWithoutAuthorizationResponse++;
}

if (str_contains($relationName, '.')) {
    // Nested relations
    $relations = explode('.', $relationName);

    foreach ($relations as $relation) {
        $result = $closure($calledOnType, $relation, $node);

        if ($result !== []) {
            return $result;
        }

        $modelReflection = $this->modelRuleHelper->findModelReflectionFromType($calledOnType);

        if ($modelReflection === null) {
            return [];
        }

        // Dynamic method return type extensions are not taken into account here.
        // So we simulate a method call to the relation here to get the return type.
        $calledOnType = $scope->getType(new MethodCall(new Node\Expr\New_(new Node\Name($modelReflection->getName())), new Node\Identifier($relation)));
    }

    return [];
}

trait CanGenerateGetHeaderActionsMethod
{
    protected function addGetHeaderActionsMethodToClass(ClassType $class): void
    {
        $actions = array_map(
            fn (string $action): string => (string) new Literal("{$this->simplifyFqn($action)}::make(),"),
            $this->getHeaderActions(),
        );

        $actionsOutput = implode(PHP_EOL . '    ', $actions);

        $method = $class->addMethod('getHeaderActions')
            ->setProtected()
            ->setReturnType('array')
            ->setBody(
                <<<PHP
                return [
                    {$actionsOutput}
                ];
                PHP
            );

        $this->configureGetHeaderActionsMethod($method);
    }

    protected function configureGetHeaderActionsMethod(Method $method): void {}
}

if ($relationship instanceof BelongsToMany) {
    $pivotTable = $relationship->getTable();
    $foreignPivotKey = $relationship->getQualifiedForeignPivotKeyName();
    $relatedPivotKey = $relationship->getQualifiedRelatedPivotKeyName();
    $parentKey = $relationship->getQualifiedParentKeyName();
    $relatedKey = $relationship->getQualifiedRelatedKeyName();

    $subQuery = $relatedModel->query()
        ->selectRaw("cast({$aggregate}({$attributeForQuery}) as {$castType})")
        ->join($pivotTable, $relatedKey, '=', $relatedPivotKey)
        ->whereColumn($foreignPivotKey, $parentKey);

    if ($modifyRelationshipQueryUsing) {
        $subQuery = $this->evaluate($modifyRelationshipQueryUsing, ['query' => $subQuery]) ?? $subQuery;
    }

    return $query->whereRaw("({$subQuery->toSql()}) {$operator} ?", [...$subQuery->getBindings(), $value]);
}

foreach ($schema->getComponents(withActions: false, withHidden: true) as $childComponent) {
    if ($childComponent->isHidden() && (! $childComponent->shouldSaveRelationshipsWhenHidden())) {
        continue;
    }

    if (
        ($childComponent->getModel() === $component->getModel()) &&
        ($childComponent->getRecord() === $component->getRecord()) &&
        ($childComponent instanceof CanEntangleWithSingularRelationships) &&
        ($childComponent->getRelationshipName() === $component->getRelationshipName()) &&
        ($childComponent->hasRelationship())
    ) {
        $componentsWithThisRelationship[] = $childComponent;

        continue;
    }

    foreach ($childComponent->getChildSchemas() as $schema) {
        $findComponentsWithThisRelationship($schema);
    }
}

foreach ($this->childComponents as $key => $childComponents) {
    if (is_array($childComponents)) {
        $this->childComponents[$key] = array_map(
            fn (Component | Action | ActionGroup | string | Htmlable $component): Component | Action | ActionGroup | string | Htmlable => match (true) {
                $component instanceof Component, $component instanceof Action, $component instanceof ActionGroup => $component->getClone(),
                default => $component,
            },
            $childComponents,
        );
    } elseif (
        ($childComponents instanceof Component) ||
        ($childComponents instanceof Action) ||
        ($childComponents instanceof ActionGroup) ||
        ($childComponents instanceof Schema)
    ) {
        $this->childComponents[$key] = $childComponents->getClone();
    }
}

